import aiocoap

class CoAPServer(aiocoap.Resource):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.sensors = {
            "temp": 25.0,
        }
        self.actuators = {
            "light": False,
        }

    def render_get(self, request):
        path = request.path.split("/")
        if len(path) == 3 and path[1] == "sensors" and path[2] in self.sensors:
            return aiocoap.Content("{}".format(self.sensors[path[2]]), content_type="text/plain")
        elif len(path) == 3 and path[1] == "actuators" and path[2] in self.actuators:
            return aiocoap.Content("{}".format(self.actuators[path[2]]), content_type="text/plain")
        else:
            return aiocoap.Response(code=aiocoap.NOT_FOUND)

    def render_put(self, request):
        path = request.path.split("/")
        if len(path) == 3 and path[1] == "actuators" and path[2] in self.actuators:
            try:
                value = float(request.payload)
                self.actuators[path[2]] = value
                return aiocoap.Response(code=aiocoap.CHANGED)
            except ValueError:
                return aiocoap.Response(code=aiocoap.BAD_REQUEST)
        else:
            return aiocoap.Response(code=aiocoap.NOT_FOUND)

